final:
module RefModule(clk,reset,a,c);input clk;
   input reset;
   input a; 
   output c; 

   wire clk;
   wire reset;   
   wire a;   
   reg c;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @ (posedge clk  or posedge dbg_halt)
  if ( reset == 1'b1) begin
    c <= 0;
  end else begin
    c <= a;
  end

endmodule
